
'use client';

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Separator } from "@/components/ui/separator";
import { MapPin, Users, Share2, ShieldAlert, PlayCircle, StopCircle, Clock, Calendar, Sun } from "lucide-react";
import Link from "next/link";
import { useToast } from '@/hooks/use-toast';
import { format } from 'date-fns';

const initialStudents = [
  { id: 'S101', name: 'Alice Johnson', status: 'Awaiting Pickup' },
  { id: 'S102', name: 'Bob Williams', status: 'Awaiting Pickup' },
  { id: 'S103', name: 'Charlie Brown', status: 'Awaiting Pickup' },
  { id: 'S104', name: 'Diana Miller', status: 'Awaiting Pickup' },
  { id: 'S105', name: 'Ethan Davis', status: 'Absent' },
  { id: 'S106', name: 'Fiona Garcia', status: 'Awaiting Pickup' },
];

type TripStatus = 'not_started' | 'in_progress' | 'ended';
type TripPeriod = 'MORNING' | 'EVENING' | 'NONE';

// --- Trip Time Configuration ---
const MORNING_TRIP_START_HOUR = 6; // 6 AM
const MORNING_TRIP_END_HOUR = 10; // 10 AM
const EVENING_TRIP_START_HOUR = 14; // 2 PM
const EVENING_TRIP_END_HOUR = 18; // 6 PM
// --------------------------------

export default function DriverDashboardPage() {
  const { toast } = useToast();
  const [students, setStudents] = useState(initialStudents);
  const [tripStatus, setTripStatus] = useState<TripStatus>('not_started');
  const [currentTripPeriod, setCurrentTripPeriod] = useState<TripPeriod>('NONE');
  const [tripTitle, setTripTitle] = useState("Today's Route");
  const [currentTime, setCurrentTime] = useState('');
  const [currentDate, setCurrentDate] = useState('');

  useEffect(() => {
     const updateDateTime = () => {
      const now = new Date();
      setCurrentTime(format(now, 'h:mm:ss a'));
      setCurrentDate(format(now, 'EEEE, MMMM do'));
    };

    const checkCurrentTime = () => {
      const currentHour = new Date().getHours();
      if (currentHour >= MORNING_TRIP_START_HOUR && currentHour < MORNING_TRIP_END_HOUR) {
        setCurrentTripPeriod('MORNING');
        setTripTitle("Today's Morning Route");
      } else if (currentHour >= EVENING_TRIP_START_HOUR && currentHour < EVENING_TRIP_END_HOUR) {
        setCurrentTripPeriod('EVENING');
        setTripTitle("Today's Evening Route");
      } else {
        setCurrentTripPeriod('NONE');
        setTripTitle("No Active Trip");
      }
    };

    updateDateTime();
    checkCurrentTime();
    
    const timer = setInterval(updateDateTime, 1000);
    // Optional: Set up an interval to check the time periodically
    const tripTimer = setInterval(checkCurrentTime, 60000); // every minute
    
    return () => {
      clearInterval(timer);
      clearInterval(tripTimer);
    }
  }, []);

  const handleShareLocation = () => {
    toast({
      title: "Location Sharing Active",
      description: "Your live location is now being shared with parents and administrators.",
    });
  };
  
  const handleStartTrip = () => {
    setTripStatus('in_progress');
    toast({
        title: `${currentTripPeriod} Trip Started`,
        description: "Admins and parents have been notified that the trip has started.",
    })
  }

  const handleEndTrip = () => {
    setTripStatus('ended');
     toast({
        title: `${currentTripPeriod} Trip Ended`,
        description: "Admins and parents have been notified that the trip is complete.",
    })
  }

  const handleAttendanceChange = (studentId: string, checked: boolean | 'indeterminate') => {
    setStudents(prevStudents =>
      prevStudents.map(student => {
        if (student.id === studentId) {
          let newStatus = student.status;
          if (checked) {
            newStatus = currentTripPeriod === 'MORNING' ? 'Picked Up' : 'Dropped Off';
          } else {
            // Revert status if unchecked
            newStatus = 'Awaiting Pickup';
          }
          return { ...student, status: newStatus };
        }
        return student;
      })
    );
  };
  
  const isTripTime = currentTripPeriod !== 'NONE';

  return (
    <div className="space-y-8">
       <div className="flex items-center justify-between">
        <div>
            <h1 className="text-3xl font-bold font-headline">Driver Dashboard</h1>
            <p className="text-muted-foreground">Welcome, John Doe. Manage your route for today.</p>
        </div>
        <div className="hidden lg:block">
            {tripStatus === 'not_started' && (
                <Button className="bg-green-600 hover:bg-green-700 text-white" size="lg" onClick={handleStartTrip} disabled={!isTripTime}>
                    <PlayCircle className="mr-2 h-4 w-4" /> Start {currentTripPeriod === 'NONE' ? 'Trip' : `${currentTripPeriod} Trip`}
                </Button>
            )}
            {tripStatus === 'in_progress' && (
                <Button className="w-full" variant="destructive" size="lg" onClick={handleEndTrip}>
                    <StopCircle className="mr-2 h-4 w-4" /> End Trip
                </Button>
            )}
             {tripStatus === 'ended' && (
                <p className="text-sm text-center text-muted-foreground">Trip for today is complete.</p>
             )}
        </div>
      </div>
      
      <div className="grid gap-8 lg:grid-cols-3">

        <div className="lg:col-span-2 space-y-8">
           <Card className="bg-gradient-to-br from-slate-900 to-slate-800 text-white shadow-2xl overflow-hidden">
                <CardContent className="p-6 flex flex-col sm:flex-row justify-between items-start gap-6">
                    <div className="flex items-center gap-4">
                        <Calendar className="h-10 w-10 text-primary flex-shrink-0"/>
                        <div>
                            <p className="text-2xl font-bold">{currentDate}</p>
                            <p className="text-slate-300">Have a safe and great day!</p>
                        </div>
                    </div>
                    <div className="text-right flex-shrink-0 self-center sm:self-auto">
                        <p className="text-5xl font-bold font-mono tracking-tight text-primary">{currentTime}</p>
                        <div className="flex items-center justify-end gap-2 text-slate-300">
                            <Sun className="h-5 w-5 text-yellow-400"/>
                            <span>72°F / 22°C</span>
                        </div>
                    </div>
                </CardContent>
            </Card>

            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2"><MapPin className="h-5 w-5 text-primary" /> {tripTitle}: North Route</CardTitle>
                    <CardDescription>Next Stop: 123 Maple St. | ETA: 8:15 AM</CardDescription>
                </CardHeader>
                <CardContent>
                    <div className="h-[300px] w-full bg-muted rounded-lg">
                        <img src="https://placehold.co/1200x600.png" alt="Map of bus route" className="w-full h-full object-cover rounded-lg" data-ai-hint="map bus route" />
                    </div>
                </CardContent>
            </Card>

            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2"><Users className="h-5 w-5 text-primary" /> Student Attendance</CardTitle>
                    <CardDescription>Check off students as they are picked up or dropped off. Enabled only during a trip.</CardDescription>
                </CardHeader>
                <CardContent>
                    <div className="space-y-4">
                        {students.map((student, index) => (
                            <div key={student.id}>
                                <div className="flex items-center justify-between">
                                    <div className="flex items-center space-x-3">
                                        <Checkbox 
                                            id={student.id} 
                                            checked={student.status === 'Picked Up' || student.status === 'Dropped Off'}
                                            disabled={student.status === 'Absent' || student.status === 'Dropped Off' || tripStatus !== 'in_progress'}
                                            onCheckedChange={(checked) => handleAttendanceChange(student.id, checked)}
                                        />
                                        <label
                                            htmlFor={student.id}
                                            className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70"
                                        >
                                            {student.name}
                                        </label>
                                    </div>
                                    <span className={`text-sm font-semibold ${
                                        student.status === 'Picked Up' ? 'text-green-600' : 
                                        student.status === 'Dropped Off' ? 'text-blue-600' :
                                        student.status === 'Absent' ? 'text-red-600' : 'text-muted-foreground'
                                    }`}>
                                        {student.status}
                                    </span>
                                </div>
                                {index < students.length - 1 && <Separator className="mt-4" />}
                            </div>
                        ))}
                    </div>
                </CardContent>
            </Card>
        </div>
        
        <div className="space-y-8">
            <Card className="lg:hidden">
                <CardHeader>
                     <CardTitle>Trip Control</CardTitle>
                </CardHeader>
                <CardContent>
                     {tripStatus === 'not_started' && (
                        <>
                        <Button className="w-full bg-green-600 hover:bg-green-700 text-white" size="lg" onClick={handleStartTrip} disabled={!isTripTime}>
                            <PlayCircle className="mr-2 h-4 w-4" /> Start {currentTripPeriod === 'NONE' ? 'Trip' : `${currentTripPeriod} Trip`}
                        </Button>
                        {!isTripTime && (
                         <p className="text-xs text-center text-muted-foreground flex items-center gap-2 justify-center mt-2">
                            <Clock className="h-4 w-4" /> Next trip is not for a while.
                         </p>
                        )}
                        </>
                     )}
                     {tripStatus === 'in_progress' && (
                        <Button className="w-full" variant="destructive" size="lg" onClick={handleEndTrip}>
                            <StopCircle className="mr-2 h-4 w-4" /> End Trip
                        </Button>
                     )}
                     {tripStatus === 'ended' && (
                        <p className="text-sm text-center text-muted-foreground">Trip for today is complete.</p>
                     )}
                </CardContent>
            </Card>
            <Card>
                <CardHeader>
                    <CardTitle>Actions</CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                    <Button className="w-full" size="lg" onClick={handleShareLocation} disabled={tripStatus !== 'in_progress'}>
                        <Share2 className="mr-2 h-4 w-4" /> Share Live Location
                    </Button>
                     <Button variant="outline" className="w-full" size="lg" asChild>
                        <Link href="/dashboard/report-safety">
                          <ShieldAlert className="mr-2 h-4 w-4" /> Report Incident
                        </Link>
                    </Button>
                </CardContent>
            </Card>
            <Card>
                <CardHeader>
                    <CardTitle>Route Summary</CardTitle>
                </CardHeader>
                <CardContent className="space-y-2 text-sm">
                    <div className="flex justify-between">
                        <span className="text-muted-foreground">Total Students:</span>
                        <span>25</span>
                    </div>
                    <div className="flex justify-between">
                        <span className="text-muted-foreground">Stops Remaining:</span>
                        <span>8</span>
                    </div>
                     <div className="flex justify-between font-medium">
                        <span className="text-muted-foreground">Trip Status:</span>
                         <span className={tripStatus === 'in_progress' ? 'text-green-600' : ''}>
                           {tripStatus === 'not_started' && 'Not Started'}
                           {tripStatus === 'in_progress' && 'In Progress'}
                           {tripStatus === 'ended' && 'Completed'}
                        </span>
                    </div>
                    <div className="flex justify-between">
                        <span className="text-muted-foreground">Estimated Completion:</span>
                        <span>{currentTripPeriod === 'MORNING' ? '8:45 AM' : '5:15 PM'}</span>
                    </div>
                </CardContent>
            </Card>
        </div>
      </div>
    </div>
  )
}
